import React from 'react';
import { Routes, Route, useNavigate } from 'react-router-dom';
import WorkflowContainer from '../components/WorkflowContainer';
import UploadStep from '../steps/uploadStep';
import DesignStep from '../steps/designStep';
import PreviewStep from '../steps/previewStage';
import DetailsStep from '../steps/detailsStep';
import DownloadStep from '../steps/downloadStep';
import { useWorkflow } from '../store/workflowContext';

const WorkflowPage = () => {
  const {
    bookDetails,
    uploadPhase, setUploadPhase,
    design, setDesign,
  } = useWorkflow();
  const nav = useNavigate();

  // Upload footer logic
  const isMeta = uploadPhase === 'metadata';
  const canProceedUpload =
    isMeta &&
    (bookDetails.title?.trim()?.length ?? 0) > 0 &&
    (bookDetails.category?.length ?? 0) > 0;

  const handleUploadNext = () => {
    if (!isMeta) return; // only actionable from metadata
    // Start Design at "analyzing"
    setDesign((d) => ({
      ...d,
      analyzed: false,
      stage: 'typography',
      saving: false,
      saveProgress: 0,
      saved: false,
    }));
    nav('/workflow/design');
  };

  // Design gating for Continue (button shown, may be disabled)
  const canProceedDesign =
    design.analyzed &&
    ((design.stage === 'typography' && !!design.typography) ||
      (design.stage === 'layout' && !!design.typography && !!design.layout) ||
      (design.stage === 'trim' && !!design.typography && !!design.layout && !!design.trim) ||
      (design.stage === 'summary'));

  return (
    <Routes>
      {/* UPLOAD */}
      <Route
        path="start"
        element={
          <WorkflowContainer
            title="Upload & Organize"
            description="Upload your manuscript files and organize them for formatting"
            step={1}
            hideNext={!isMeta}                 // show Continue only on metadata phase
            canProceed={canProceedUpload}
            onNext={handleUploadNext}
            disableSavePrompt={false}          // <-- SHOW the Save & Continue modal
            onPrevious={() => {
              if (uploadPhase === 'metadata') return setUploadPhase('ready');
              if (uploadPhase === 'ready')    return setUploadPhase('select');
              nav('/');
            }}
          >
            <UploadStep />
          </WorkflowContainer>
        }
      />

      {/* DESIGN */}
      <Route
        path="design"
        element={
          <WorkflowContainer
            title="Design Your Book"
            description="Customize typography, layout, and format with AI-powered recommendations"
            step={2}
            hideNext={false}
            canProceed={canProceedDesign}
            onNext={() => {
              if (design.stage === 'typography') return setDesign((d) => ({ ...d, stage: 'layout' }));
              if (design.stage === 'layout')     return setDesign((d) => ({ ...d, stage: 'trim' }));
              if (design.stage === 'trim')       return setDesign((d) => ({ ...d, stage: 'summary' }));
              // summary → save then Preview (DesignStep navigates once save hits 100%)
              if (!design.saving && !design.saved) {
                return setDesign((d) => ({ ...d, saving: true, saveProgress: 0 }));
              }
              nav('/workflow/preview');
            }}
            onPrevious={() => {
              if (design.stage === 'summary') return setDesign((d) => ({ ...d, stage: 'trim' }));
              if (design.stage === 'trim')    return setDesign((d) => ({ ...d, stage: 'layout' }));
              if (design.stage === 'layout')  return setDesign((d) => ({ ...d, stage: 'typography' }));
              nav('/workflow/start');
            }}
          >
            <DesignStep />
          </WorkflowContainer>
        }
      />

      {/* PREVIEW */}
      <Route
        path="preview"
        element={
          <WorkflowContainer
            title="Preview"
            description="Check how pages will look with your chosen design"
            step={3}
            hideNext={false}
            canProceed={true}
          >
            <PreviewStep />
          </WorkflowContainer>
        }
      />

      {/* DETAILS */}
      <Route
        path="details"
        element={
          <WorkflowContainer
            title="Details"
            description="Add book metadata and publishing options"
            step={4}
            hideNext={false}
            canProceed={true}
          >
            <DetailsStep />
          </WorkflowContainer>
        }
      />

      {/* DOWNLOAD */}
      <Route
        path="download"
        element={
          <WorkflowContainer
            title="Download"
            description="Download formatted files and upload packages"
            step={5}
            hideNext={false}
            canProceed={true}
          >
            <DownloadStep />
          </WorkflowContainer>
        }
      />

      {/* index mirrors /start */}
      <Route
        index
        element={
          <WorkflowContainer
            title="Upload & Organize"
            description="Upload your manuscript files and organize them for formatting"
            step={1}
            hideNext={!isMeta}
            canProceed={canProceedUpload}
            onNext={handleUploadNext}
            disableSavePrompt={false}          // <-- SHOW the Save & Continue modal
            onPrevious={() => {
              if (uploadPhase === 'metadata') return setUploadPhase('ready');
              if (uploadPhase === 'ready')    return setUploadPhase('select');
              nav('/');
            }}
          >
            <UploadStep />
          </WorkflowContainer>
        }
      />
    </Routes>
  );
};

export default WorkflowPage;
